/*
  Global design system based on the provided community guide layout.
  Colors, typography, and spacing are tuned to closely match the screenshot
  (flat pastel coral header, light blue-grey page background, white cards).
*/

:root {
  /* Brand & palette */
  --color-primary: #FF8266;           /* Coral header & primary accents */
  --color-primary-soft: #F6F9FC;      /* Very light background */
  --color-secondary: #62C7E6;         /* Light blue accents (badge, highlights) */
  --color-secondary-soft: #F5F7FA;    /* Soft secondary background */
  --color-accent-coral: #FF8266;
  --color-accent-green: #00B76A;

  --color-neutral-0: #FFFFFF;
  --color-neutral-50: #FAFBFD;
  --color-neutral-100: #F6F9FC;       /* Main page background, close to screenshot */
  --color-neutral-200: #E4EAF0;       /* Subtle borders, separators */
  --color-neutral-500: #7A8A99;       /* Muted text */
  --color-neutral-700: #3C4A57;       /* Primary body text */

  --color-success: #28A745;
  --color-error: #E74C3C;
  --color-warning: #F1C40F;
  --color-info: #3498DB;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', Menlo, monospace;

  --font-size-base: 15px;             /* Between 14-16px for body */
  --font-size-small: 13px;
  --font-size-h1: 30px;
  --font-size-h2: 24px;
  --font-size-h3: 19px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Radii & shadows */
  --radius-sm: 4px;                   /* Buttons, cards */
  --radius-md: 6px;
  --shadow-card: 0 4px 10px rgba(15, 35, 52, 0.06);
}

/* Global element resets & base styles */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-base);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-700);
  background-color: var(--color-neutral-100);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: var(--color-primary);
  text-decoration: none;
}

a:hover,
a:focus-visible {
  text-decoration: underline;
}

button {
  font-family: inherit;
}

.u-visually-hidden {
  border: 0;
  clip: rect(0 0 0 0);
  height: 1px;
  width: 1px;
  margin: -1px;
  padding: 0;
  overflow: hidden;
  position: absolute;
}

.container {
  max-width: 1120px;                  /* Slightly inset from full width */
  margin: 0 auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

/* Header layout & styling */

.site-header {
  position: relative;
  z-index: 10;
}

.site-header-top {
  background-color: var(--color-primary);
  color: var(--color-neutral-0);
}

.header-inner {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  padding-top: var(--space-3);         /* approx 16px */
  padding-bottom: var(--space-3);
  min-height: 80px;                    /* Matches tall coral bar in design */
}

/* Playful illustration block in the upper-left corner.
   Use a raster image (PNG/JPG) if available; falls back to a flat shape. */
.header-illustration {
  position: absolute;
  left: 0;
  bottom: -18px;                       /* Overlaps content slightly like screenshot */
  width: 260px;
  height: 130px;
  background-color: transparent;
  background-image: url('assets/header-illustration.png');
  background-repeat: no-repeat;
  background-size: contain;
  background-position: left bottom;
  pointer-events: none;
}

/* Logo placeholder: entirely visually hidden but keeps a semantic brand link. */
.site-logo {
  position: absolute;
  left: var(--space-4);
  top: 50%;
  transform: translateY(-50%);
  text-decoration: none;
  color: var(--color-neutral-0);
}

/* Primary navigation */

.site-nav {
  position: relative;
  z-index: 1;                          /* Above illustration */
}

.site-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-4);                 /* Even spacing across header */
}

.site-nav-item {
  white-space: nowrap;
}

.site-nav-link {
  display: inline-block;
  padding: 4px 2px;
  text-transform: uppercase;
  font-family: var(--font-heading);
  font-size: 14px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.08em;
  color: var(--color-neutral-0);
  text-decoration: none;
}

.site-nav-link:hover,
.site-nav-link:focus-visible {
  text-decoration: none;
  opacity: 0.85;                       /* Subtle hover similar to flat design */
}

.site-nav-link.is-active {
  border-bottom: 2px solid var(--color-neutral-0);
  padding-bottom: 2px;
}

/* Main content wrapper */

.site-main {
  padding-top: var(--space-6);         /* Space between header and first content */
  padding-bottom: var(--space-6);
}

/* Generic card pattern (aligns with screenshot but not instantiated here) */

.card {
  background-color: var(--color-neutral-0);
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-card);
  overflow: hidden;
}

.card-media {
  position: relative;
  width: 100%;
  overflow: hidden;
}

.card-media img {
  display: block;
  width: 100%;
}

.card-badge {
  position: absolute;
  left: 24px;
  bottom: -22px;                       /* Overlaps between image and content */
  width: 56px;
  height: 56px;
  border-radius: 50%;
  background-color: var(--color-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-neutral-0);
  font-size: 11px;
  font-weight: var(--font-weight-semibold);
}

.card-body {
  padding: 32px 24px 24px;             /* Top padding accounts for overlapping badge */
}

.card-title {
  margin: 0 0 6px;
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-accent-coral);
}

.card-meta {
  margin: 0 0 8px;
  color: var(--color-neutral-500);
  font-size: 13px;
}

.card-text {
  margin: 0;
  font-size: var(--font-size-base);
}

/* Footer styling */

.site-footer {
  background-color: var(--color-neutral-0);
  border-top: 1px solid var(--color-neutral-200);
  color: var(--color-neutral-500);
}

.footer-inner {
  padding-top: var(--space-4);
  padding-bottom: var(--space-4);
}

.footer-primary {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-4);
  margin-bottom: var(--space-3);
}

.footer-branding {
  max-width: 360px;
}

.footer-logo {
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-neutral-700);
  margin-bottom: 4px;
}

.footer-tagline {
  margin: 0;
  font-size: var(--font-size-small);
  color: var(--color-neutral-500);
}

.footer-nav {
  flex: 1 1 auto;
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2) var(--space-4);
}

.footer-nav-item {
}

.footer-nav-link {
  font-size: var(--font-size-small);
  font-weight: var(--font-weight-medium);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--color-neutral-500);
}

.footer-nav-link:hover,
.footer-nav-link:focus-visible {
  color: var(--color-primary);
  text-decoration: none;
}

.footer-secondary {
  border-top: 1px solid var(--color-neutral-200);
  padding-top: var(--space-2);
}

.footer-meta {
  margin: 0;
  font-size: 12px;
  color: var(--color-neutral-500);
}

/* Basic responsive tweaks (no extra interactive controls) */

@media (max-width: 960px) {
  .site-nav-list {
    gap: var(--space-3);
    flex-wrap: wrap;
  }

  .header-inner {
    padding-left: var(--space-5);
    padding-right: var(--space-5);
  }

  .header-illustration {
    width: 210px;
    height: 110px;
  }
}

@media (max-width: 640px) {
  .site-nav-list {
    justify-content: flex-start;
    row-gap: var(--space-2);
  }

  .header-inner {
    justify-content: flex-start;
  }

  .site-main {
    padding-top: var(--space-5);
    padding-bottom: var(--space-5);
  }

  .footer-primary {
    flex-direction: column;
    align-items: flex-start;
  }
}
